 1	import type { FC } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { ProviderModelRef } from '@kubev2v/types';
 5	import { Button, ButtonVariant } from '@patternfly/react-core';
 6	
 7	import { getResourceUrl } from '../../../modules/Providers/utils/helpers/getResourceUrl';
 8	import { ProviderCreateSource, TELEMETRY_EVENTS } from '../../../utils/analytics/constants';
 9	import { useForkliftAnalytics } from '../../../utils/analytics/hooks/useForkliftAnalytics';
10	import { useForkliftTranslation } from '../../../utils/i18n';
11	
12	type ProvidersAddButtonProps = {
13	  namespace?: string;
14	  testId?: string;
15	  canCreate?: boolean;
16	};
17	
18	const ProvidersAddButton: FC<ProvidersAddButtonProps> = ({ canCreate, namespace, testId }) => {
19	  const { t } = useForkliftTranslation();
20	  const navigate = useNavigate();
21	  const { trackEvent } = useForkliftAnalytics();
22	
23	  const providersListURL = getResourceUrl({
24	    namespace,
25	    namespaced: namespace !== undefined,
26	    reference: ProviderModelRef,
27	  });
28	
29	  const onClick = () => {
30	    trackEvent(TELEMETRY_EVENTS.PROVIDER_CREATE_CLICKED, {
31	      createSource: ProviderCreateSource.ProvidersPage,
32	      namespace,
33	    });
34	
35	    navigate(`${providersListURL}/~new`);
36	  };
37	
38	  return (
39	    <Button
40	      data-testid={testId}
41	      variant={ButtonVariant.primary}
42	      onClick={onClick}
43	      isDisabled={!canCreate}
44	    >
45	      {t('Create provider')}
46	    </Button>
47	  );
48	};
49	
50	export default ProvidersAddButton;

